import React, { useState, useEffect } from 'react';
import { ethers } from 'ethers';
import { getContracts, getUser } from '../utils/web3';

function Marketplace() {
  const [listings, setListings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState({ type: '', text: '' });
  const [purchasing, setPurchasing] = useState(null);
  const [nftMetadata, setNftMetadata] = useState({});

  useEffect(() => {
    fetchListings();
  }, []);

  // Fetch metadata from IPFS URL
  const fetchMetadata = async (tokenURI) => {
    try {
      if (!tokenURI) return null;
      
      // Handle both IPFS URLs and data URLs
      if (tokenURI.startsWith('http')) {
        const response = await fetch(tokenURI);
        return await response.json();
      } else if (tokenURI.startsWith('data:application/json;base64,')) {
        // Handle base64 encoded metadata
        const base64Data = tokenURI.split(',')[1];
        const jsonString = atob(base64Data);
        return JSON.parse(jsonString);
      } else {
        // Try to parse as JSON string
        try {
          return JSON.parse(tokenURI);
        } catch {
          return null;
        }
      }
    } catch (error) {
      console.error('Error fetching metadata:', error);
      return null;
    }
  };

  const fetchListings = async () => {
    try {
      const { marketplace } = getContracts();
      
      // Check if marketplace contract is initialized
      if (!marketplace) {
        console.warn("Marketplace contract not initialized");
        setMessage({ type: 'error', text: 'Please connect your wallet first' });
        setLoading(false);
        return;
      }
      
      // Get total listings count
      const counter = await marketplace.listingCounter();
      const totalListings = parseInt(counter.toString());
      
      // Fetch all active listings
      const activeListings = [];
      
      for (let i = 1; i <= totalListings; i++) {
        try {
          const listing = await marketplace.listings(i);
          
          if (listing.active) {
            activeListings.push({
              id: i,
              seller: listing.seller,
              tokenAddress: listing.tokenAddress,
              tokenId: listing.tokenId.toString(),
              price: listing.price.toString(),
              amount: listing.amount.toString(),
              isERC1155: listing.isERC1155
            });
            
            // Fetch metadata for this NFT
            try {
              // Get the token contract to fetch tokenURI
              const { erc721, erc1155 } = getContracts();
              const tokenContract = listing.isERC1155 ? erc1155 : erc721;
              
              if (tokenContract) {
                const tokenURI = await tokenContract.tokenURI(listing.tokenId);
                const metadata = await fetchMetadata(tokenURI);
                if (metadata) {
                  setNftMetadata(prev => ({
                    ...prev,
                    [`${listing.isERC1155 ? '1155' : '721'}-${listing.tokenId}`]: metadata
                  }));
                }
              }
            } catch (error) {
              console.error('Error fetching NFT metadata:', error);
            }
          }
        } catch (error) {
          console.error(`Error fetching listing ${i}:`, error);
        }
      }
      
      setListings(activeListings);
    } catch (error) {
      console.error("Error fetching listings:", error);
      setMessage({ type: 'error', text: 'Failed to load listings' });
    } finally {
      setLoading(false);
    }
  };

  const handlePurchase = async (listingId, price) => {
    setPurchasing(listingId);
    setMessage({ type: '', text: '' });
    
    try {
      const { marketplace } = getContracts();
      const { address } = getUser();
      
      if (!address) {
        throw new Error('Please connect your wallet first');
      }
      
      if (!marketplace) {
        throw new Error('Marketplace contract not initialized. Please connect your wallet first.');
      }
      
      const tx = await marketplace.purchaseToken(listingId, {
        value: price
      });
      
      await tx.wait();
      
      setMessage({ 
        type: 'success', 
        text: 'NFT purchased successfully!' 
      });
      
      // Refresh listings
      fetchListings();
      
    } catch (error) {
      console.error("Purchase error:", error);
      setMessage({ 
        type: 'error', 
        text: error.message || 'Failed to purchase NFT' 
      });
    } finally {
      setPurchasing(null);
    }
  };

  const formatPrice = (priceWei) => {
    return ethers.formatEther(priceWei);
  };

  const formatAddress = (address) => {
    if (!address) return '';
    return `${address.substring(0, 6)}...${address.substring(address.length - 4)}`;
  };

  if (loading) {
    return (
      <div className="section">
        <h2 className="section-title">Marketplace</h2>
        <div className="loading">Loading listings...</div>
      </div>
    );
  }

  return (
    <div className="section">
      <h2 className="section-title">NFT Marketplace Listings</h2>
      
      {message.text && (
        <div className={message.type} style={{ marginBottom: '20px' }}>
          {message.text}
        </div>
      )}

      {listings.length === 0 ? (
        <div className="loading">
          No active listings available. Be the first to list an NFT!
        </div>
      ) : (
        <div className="nft-grid">
          {listings.map((listing) => (
            <div key={listing.id} className="nft-card">
              <div className="nft-image">
                {nftMetadata[`${listing.isERC1155 ? '1155' : '721'}-${listing.tokenId}`]?.image ? (
                  <img 
                    src={nftMetadata[`${listing.isERC1155 ? '1155' : '721'}-${listing.tokenId}`].image}
                    alt={nftMetadata[`${listing.isERC1155 ? '1155' : '721'}-${listing.tokenId}`].name || 'NFT'}
                    style={{
                      width: '100%',
                      height: '100%',
                      objectFit: 'cover',
                      borderRadius: '8px'
                    }}
                    onError={(e) => {
                      e.target.style.display = 'none';
                      e.target.nextSibling.style.display = 'flex';
                    }}
                  />
                ) : null}
                <div style={{
                  width: '100%',
                  height: '100%',
                  background: 'linear-gradient(45deg, #1a1a2e, #16213e)',
                  display: nftMetadata[`${listing.isERC1155 ? '1155' : '721'}-${listing.tokenId}`]?.image ? 'none' : 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: '#00ff00',
                  fontSize: '14px'
                }}>
                  NFT #{listing.tokenId}
                  <br />
                  {listing.isERC1155 ? 'ERC-1155' : 'ERC-721'}
                </div>
              </div>
              
              <div className="nft-info">
                <div className="nft-name">
                  {nftMetadata[`${listing.isERC1155 ? '1155' : '721'}-${listing.tokenId}`]?.name || 
                   (listing.isERC1155 ? 'Multi Token' : 'Unique NFT')} #{listing.tokenId}
                </div>
                
                <div className="nft-price">
                  {formatPrice(listing.price)} ETH
                </div>
                
                {listing.isERC1155 && (
                  <div style={{ fontSize: '14px', color: '#aaa', marginBottom: '10px' }}>
                    Amount: {listing.amount}
                  </div>
                )}
                
                <div style={{ fontSize: '12px', color: '#888', marginBottom: '10px' }}>
                  Seller: {formatAddress(listing.seller)}
                </div>
                
                <button 
                  className="buy-btn"
                  onClick={() => handlePurchase(listing.id, listing.price)}
                  disabled={purchasing === listing.id}
                >
                  {purchasing === listing.id ? 'Purchasing...' : 'Buy Now'}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
      
      <div style={{ marginTop: '20px', textAlign: 'center' }}>
        <button 
          onClick={fetchListings}
          style={{
            background: 'transparent',
            border: '1px solid #00ff00',
            color: '#00ff00',
            padding: '10px 20px',
            borderRadius: '6px',
            cursor: 'pointer'
          }}
        >
          Refresh Listings
        </button>
      </div>
    </div>
  );
}

export default Marketplace;
